+    use crate::gen_server::{GenServer, Reply, SystemMsg};
+    use std::future::Future;
+    use std::pin::Pin;
+
+    /// Chat room state: holds a bounded message history.
+    struct ChatRoom {
+        history: Vec<String>,
+        max_history: usize,
+    }
+
+    /// Synchronous requests (call): operations that return a response.
+    enum ChatCall {
+        /// Get the current message history.
+        GetHistory,
+        /// Get the number of messages.
+        Count,
+    }
+
+    /// Asynchronous messages (cast): fire-and-forget operations.
+    enum ChatCast {
+        /// Post a message to the room.
+        Post(String),
+        /// Clear all messages.
+        Clear,
+    }
+
+    impl GenServer for ChatRoom {
+        type Call = ChatCall;
+        type Reply = Vec<String>;
+        type Cast = ChatCast;
+        type Info = SystemMsg;
+
+        fn handle_call(
+            &mut self,
+            _cx: &Cx,
+            request: ChatCall,
+            reply: Reply<Vec<String>>,
+        ) -> Pin<Box<dyn Future<Output = ()> + Send + '_>> {
+            match request {
+                ChatCall::GetHistory => {
+                    let _ = reply.send(self.history.clone());
+                }
+                ChatCall::Count => {
+                    // Encode count as a single-element vec to satisfy the Reply type.
+                    let _ = reply.send(vec![self.history.len().to_string()]);
+                }
+            }
+            Box::pin(async {})
+        }
+
+        fn handle_cast(
+            &mut self,
+            _cx: &Cx,
+            msg: ChatCast,
+        ) -> Pin<Box<dyn Future<Output = ()> + Send + '_>> {
+            match msg {
+                ChatCast::Post(text) => {
+                    self.history.push(text);
+                    if self.history.len() > self.max_history {
+                        self.history.remove(0);
+                    }
+                }
+                ChatCast::Clear => {
+                    self.history.clear();
+                }
+            }
+            Box::pin(async {})
+        }
+    }
+
+    impl ChatRoom {
+        fn new(max_history: usize) -> Self {
+            Self {
+                history: Vec::new(),
+                max_history,
+            }
+        }
+    }
